    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n/*\n * This program tests for hugepage leaks after DIO writes to a file using a\n * hugepage as the user buffer. During DIO, the user buffer is pinned and\n * should be properly unpinned upon completion. This patch verifies that the\n * kernel correctly unpins the buffer at DIO completion for both aligned and\n * unaligned user buffer offsets (w.r.t page boundary), ensuring the hugepage\n * is freed upon unmapping.\n */\n\n#define _GNU_SOURCE\n#include <stdio.h>\n#include <sys/stat.h>\n#include <stdlib.h>\n#include <fcntl.h>\n#include <stdint.h>\n#include <unistd.h>\n#include <string.h>\n#include <sys/mman.h>\n#include \"vm_util.h\"\n#include \"kselftest.h\"\n\n#ifndef STATX_DIOALIGN\n#define STATX_DIOALIGN\t\t0x00002000U\n#endif\n\nvoid check_dio_alignment(size_t pagesize)\n{\n\tint fd;\n\tstruct statx stx;\n\tunsigned int dio_align = 1;\n\n\tfd = open(\"/tmp\", O_TMPFILE | O_RDWR, 0664);\n\tif (fd < 0)\n\t\tksft_exit_skip(\"Unable to allocate file: %s\\n\", strerror(errno));\n\n\tif (statx(fd, \"\", AT_EMPTY_PATH, STATX_DIOALIGN, &stx) == 0 &&\n\t\t\t\t(stx.stx_mask & STATX_DIOALIGN))\n\t\tdio_align = stx.stx_dio_offset_align;\n\n\tclose(fd);\n\n\tif ((pagesize / 2) % dio_align != 0)\n\t\tksft_exit_skip(\"DIO alignment (%u) incompatible with sub-page offset %lu\\n\",\n\t\t\t\tdio_align, pagesize / 2);\n}\n\nvoid run_dio_using_hugetlb(unsigned int start_off, unsigned int end_off)\n{\n\tint fd;\n\tchar *buffer =  NULL;\n\tchar *orig_buffer = NULL;\n\tsize_t h_pagesize = 0;\n\tsize_t writesize;\n\tint free_hpage_b = 0;\n\tint free_hpage_a = 0;\n\tconst int mmap_flags = MAP_PRIVATE | MAP_ANONYMOUS | MAP_HUGETLB;\n\tconst int mmap_prot  = PROT_READ | PROT_WRITE;\n\n\twritesize = end_off - start_off;\n\n\t/* Get the default huge page size */\n\th_pagesize = default_huge_page_size();\n\tif (!h_pagesize)\n\t\tksft_exit_fail_msg(\"Unable to determine huge page size\\n\");\n\n\t/* Open the file to DIO */\n\tfd = open(\"/tmp\", O_TMPFILE | O_RDWR | O_DIRECT, 0664);\n\tif (fd < 0)\n\t\tksft_exit_fail_perror(\"Error opening file\\n\");\n\n\t/* Get the free huge pages before allocation */\n\tfree_hpage_b = get_free_hugepages();\n\tif (free_hpage_b == 0) {\n\t\tclose(fd);\n\t\tksft_exit_skip(\"No free hugepage, exiting!\\n\");\n\t}\n\n\t/* Allocate a hugetlb page */\n\torig_buffer = mmap(NULL, h_pagesize, mmap_prot, mmap_flags, -1, 0);\n\tif (orig_buffer == MAP_FAILED) {\n\t\tclose(fd);\n\t\tksft_exit_fail_perror(\"Error mapping memory\\n\");\n\t}\n\tbuffer = orig_buffer;\n\tbuffer += start_off;\n\n\tmemset(buffer, 'A', writesize);\n\n\t/* Write the buffer to the file */\n\tif (write(fd, buffer, writesize) != (writesize)) {\n\t\tmunmap(orig_buffer, h_pagesize);\n\t\tclose(fd);\n\t\tksft_exit_fail_perror(\"Error writing to file\\n\");\n\t}\n\n\t/* unmap the huge page */\n\tmunmap(orig_buffer, h_pagesize);\n\tclose(fd);\n\n\t/* Get the free huge pages after unmap*/\n\tfree_hpage_a = get_free_hugepages();\n\n\tksft_print_msg(\"No. Free pages before allocation : %d\\n\", free_hpage_b);\n\tksft_print_msg(\"No. Free pages after munmap : %d\\n\", free_hpage_a);\n\n\t/*\n\t * If the no. of free hugepages before allocation and after unmap does\n\t * not match - that means there could still be a page which is pinned.\n\t */\n\tksft_test_result(free_hpage_a == free_hpage_b,\n\t\t\t \"free huge pages from %u-%u\\n\", start_off, end_off);\n}\n\nint main(void)\n{\n\tsize_t pagesize = psize();\n\n\tksft_print_header();\n\n\tcheck_dio_alignment(pagesize);\n\n\t/* Check if huge pages are free */\n\tif (!get_free_hugepages())\n\t\tksft_exit_skip(\"No free hugepage, exiting\\n\");\n\n\tksft_set_plan(4);\n\n\t/* start and end is aligned to pagesize */\n\trun_dio_using_hugetlb(0, (pagesize * 3));\n\n\t/* start is aligned but end is not aligned */\n\trun_dio_using_hugetlb(0, (pagesize * 3) - (pagesize / 2));\n\n\t/* start is unaligned and end is aligned */\n\trun_dio_using_hugetlb(pagesize / 2, (pagesize * 3));\n\n\t/* both start and end are unaligned */\n\trun_dio_using_hugetlb(pagesize / 2, (pagesize * 3) + (pagesize / 2));\n\n\tksft_finished();\n}\n"}",
